function splitSensors(text){return String(text||'').split(',').map(x=>x.trim()).filter(Boolean)}
function getSensorDetailLink(label){let clean=String(label||'').toLowerCase().replace(/[()]/g,' ');let hit=sensorDetailLinks.find(([key])=>clean.includes(key));return hit?hit[1]:'https://www.google.com/search?q='+encodeURIComponent(label+' sensor technical details')}
