function TopControls({action='Export Report'}){return <div className="topControls"><button className="control"><CalendarDays size={17}/> May 8 – May 14, 2025</button><button className="control"><Filter size={17}/> All Regions</button><button className="primary"><Download size={18}/> {action}</button></div>}
